    # Sum up the capacities in a descendant order
    descendant_ports = {}
    for node in graph_copy.nodes(data=True):
        if node[1]['type'] == ['EK_PACKET_SWITCH']:
            descendant_ports[node[0]] = port_capacity[node[0]]
            fordecessor_node_name, predecessor_edge_type = None, None
            for predecessor_edge in graph_copy.out_edges(node[0]):
                if predecessor_edge[2]['type'] == 'RK_CONTAINS' and predecessor_edge[1][1]['type'] == ['EK_PORT']:
                    predecessor_node_name = predecessor_edge[1][0]
                    predecessor_edge_type = predecessor_edge[2]['type']
                    break
            if predecessor_node_name:
                descendant_ports[node[0]] += port_capacity[predecessor_node_name]
                for predecessor_port in graph_copy.nodes(data=True):
                    if predecessor_port[1]['name'].startswith(node_name) and predecessor_port[1]['type'] == ['EK_PORT']:
                        descendant_ports[node[0]] += port_capacity[predecessor_port[0]]

    # Add the capacities for 'updated_graph'
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    graph_json['nodes'].extend([
        {'id': f'capacity_{descendant_node}', 'label': f'Capacity of {descendant_node}', 'value': descendant_capacity}
        for descendant_node, descendant_capacity in descendant_ports.items()
    ])

    # Create a new node for each descendant with label 'Capacity_of_span_id'
    for descendant_node, descendant_capacity in descendant_ports.items():
        for span_id in descendant_node.split('.')[:-1]:
