def process_graph(graph_data):
    # Create a graph copy to avoid modifying the input graph
    graph_copy = graph_data.copy()

    # Function to get parent node based on target node name and hierarchy
    def get_parent_name(target_name, hierarchy):
        for node_name, node_type in list(graph_copy.nodes(data=("name", "type"))):
            if node_name.startswith(target_name) and hierarchy in node_type:
                return node_name
        return None

    # Function to get physical capacity of a node
    def get_node_capacity(node):
        if "EK_PORT" in node[1]['type']:
            return int(node[2]['physical_capacity_bps'])
        parent_name = get_parent_name(node[0], 'EK_' + node[1]['type'][0].upper())
        if parent_name is None:
            return 0
        else:
            parent_nodes = [n for n in graph_copy.nodes if n[0] == parent_name]
            capacity = sum(get_node_capacity(parent_node) for parent_node in parent_nodes)
            return capacity

    # Remove node and its edges from the graph
    target_node_name = 'ju1.s1.s2c3'
    target_node = [
        node[0] == target_node_name for node in graph_copy.nodes(data=("name", "type"))
    ][0]
    if target_node:
        graph_copy.remove_node(target_node)

    # Update edges in the graph
    edges = list(graph_copy.edges(data="weight"))
    graph_copy.clear_edges()
    for edge in edges:
        src, dst, weight = edge
        if dst != target_node:
            graph_copy.add_edge(src, dst, weight)

    # Rank direct child nodes of ju1.s1 based on physical_capacity_bps
    rank_direct_children = []
    ju1_s1_parent = get_parent_name('ju1.s1', "EK_JUPITER")
    if ju1_s1_parent is not None:
        direct_children = [
            node
            for node in graph_copy.nodes
            if node[0].startswith(ju1_s1_parent + ". ")
            and "EK_SUPERBLOCK" in node[1]['type']
        ]
        for child_node in direct_children:
            capacity = 0
            superblock_parent = get_parent_name(
                child_node[0], "EK_SUPERBLOCK"
            )
            if superblock_parent is not None:
                agg_block_parent = get_parent_name(
                    superblock_parent, "EK_AGG_BLOCK"
                )
