                    port_parent = get_parent_name(agg_block_parent, "EK_AGG_BLOCK")
                    if port_parent is not None:
                        capacity = get_node_capacity(port_parent)
            rank_direct_children.append((child_node[0], capacity))

    # Sort rank_direct_children based on capacity
    rank_direct_children.sort(key=lambda x: x[1], reverse=True)

    # Return the result as a JSON object
    result = {
        "type": "list",
        "data": rank_direct_children,
        "updated_graph": nx.readwrite.json_graph.node_link_data(graph_copy),
    }
    return result

