    graph_copy = graph_data.copy()

    # Find the node to be removed
    node_to_remove = next((node for node in graph_copy.nodes() if node['name'] == 'ju1.a2.m4.s3c8'), None)

    if node_to_remove:
        # Remove the node and its incident edges
        graph_copy.remove_node(node_to_remove['name'])

        # Update the physical capacity of affected nodes
        def update_physical_capacity(node):
            if 'physical_capacity_bps' in node:
                return node['physical_capacity_bps']
            else:
                # Recursively sum the physical capacity of contained ports
                return sum(update_physical_capacity(getattr(node, edge[1])['attributes']) for edge in graph_copy.in_edges(node['name']) if edge[1] == 'RK_CONTAINS')

        # Update the physical capacity of nodes containing the removed node
        visited = set()
        for node in graph_copy.nodes():
            if 'EK_PORT' in node['type'] and 'physical_capacity_bps' not in node:
                stack = [node]
                while stack:
                    current_node = stack.pop()
                    if current_node not in visited:
                        visited.add(current_node)
                        stack.extend([n for e in graph_copy.in_edges(current_node['name']) if e[1] == 'RK_CONTAINS' for n in graph_copy.nodes() if n['name'] == e[0]])

                # Update the physical capacity of the node
                port = next((n for e in graph_copy.in_edges(node['name']) if e[1] == 'RK_CONTAINS' for n in graph_copy.nodes() if n['name'] == e[0]), None)
                if port:
                    port['physical_capacity_bps'] = update_physical_capacity(node)

        # Count EK_PACKET_SWITCH in ju1.a2.m4
